package comp310.tests.hw03;

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

import java.awt.Color;
import java.awt.Graphics;
import java.awt.Point;

import hw03.model.Ball;
import hw03.model.strategy.ExplodingStrategy;
import hw03.model.strategy.StraightStrategy;
import provided.utils.displayModel.IDimension;
import provided.utils.dispatcher.IDispatcher;
import provided.utils.dispatcher.impl.SequentialDispatcher;

class MyStrategyTest {

    private final IDimension mockDim = new IDimension() {
        public int getWidth() { return 800; }
        public int getHeight() { return 600; }
    };

    @Test
    void testExplodingStrategySpawnsBallOnBounce() {
        IDispatcher<Graphics> disp = new SequentialDispatcher<>();
        Ball ball = new Ball(new Point(100, 100), new Point(5, 5), Color.RED, 10, mockDim, new ExplodingStrategy());
        disp.addObserver(ball);

        assertEquals(1, disp.getAllObservers().size(), "Should have 1 ball initially");

        // Trigger a bounce manually
        ball.hasBounced()[0] = true;

        // Update state
        ball.getStrategy().updateState(disp, ball);

        assertEquals(2, disp.getAllObservers().size(), "Should have 2 balls after explosion");
        assertFalse(ball.hasBounced()[0], "Bounced flag should be reset");
    }
}

